record.field:
if not records:
    raise UserError("No records selected.")

move_type = records[0].move_type
if move_type in ('out_invoice', 'out_refund'):
    rec_type = 'customer'
elif move_type in ('in_invoice', 'in_refund'):
    rec_type = 'vendor'
else:
    raise UserError("This action only works on Customer Invoices or Vendor Bills.")

partners = records.mapped('partner_id.commercial_partner_id')
if not partners:
    raise UserError("No partner found on the selected records.")

wizard = env['account.payment.reconcile.wizard'].sudo().create({
    'company_id': env.company.id,
    'reconcile_type': rec_type,
})

total = 0
processed = 0

for partner in partners:
    if rec_type == 'customer':
        count = wizard._reconcile_customer_partner(partner)
    else:
        count = wizard._reconcile_vendor_partner(partner)
    if count:
        total += count
        processed += 1

if total == 0:
    raise UserError(
        "No new reconciliations.\n"
        "Make sure partners have posted documents and unreconciled payments."
    )

action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': 'Reconciliation Complete',
        'message': 'Reconciled %d line(s) for %d partner(s) — oldest to newest.' % (total, processed),
        'type': 'success',
        'sticky': False,
    },
}
